addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request))
})

async function handleRequest(request) {
  const url = new URL(request.url)
  if (url.pathname === '/login') {
    return authenticateUser(request)
  } else {
    return fetch(request) // Continue to next middleware
  }
}

async function authenticateUser(request) {
  const { username, password } = await request.json()
  
  if (!username || !password) {
    return new Response('Missing credentials', { status: 401 })
  }

  // Retrieve user database from KV namespace
  let users = await USERS_NAMESPACE.get("users")
  users = JSON.parse(users)
  
  const user = users.find((user) => user.username === username && user.password === password);

  if (!user) {
    return new Response('Invalid credentials', { status: 401 })
  }

  // Generate a session token and store it in KV namespace for future use
  const sessionToken = Math.random().toString(36).substring(2, 15);
  
  await SESSIONS_NAMESPACE.put("session_" + user.id, JSON.stringify({ token: sessionToken }))

  return new Response('OK', { status: 200 }) // TODO: send back the session token in the response body instead of 'OK'
}